installer-gui-script.script:

function installCheck() {
    // Require macOS 11.0 or later
    var sys = system;
    if (sys.version.ProductVersion) {
        var v = sys.version.ProductVersion.split(".");
        var major = parseInt(v[0]);
        var minor = parseInt(v[1]);
        if (major < 11) {
            my.result.type = "Fatal";
            my.result.message = "AI Competency Agent requires macOS 11.0 (Big Sur) or later.";
            return false;
        }
    }
    return true;
}
